    IfxPort_Mode_inputPullUp            = 0x10U,
    IfxPort_Mode_outputPushPullGeneral  = 0x80U,
    IfxPort_Mode_outputPushPullAlt1     = 0x88U,
    IfxPort_Mode_outputPushPullAlt2     = 0x90U,
    IfxPort_Mode_outputPushPullAlt3     = 0x98U,
